  function isDesktop(){ return window.matchMedia(DESKTOP).matches; }

  function disableClickOnToggle(toggle){
    // ЧТО гасим: любые попытки клика/клавиш на самом тоггле
    const cancel = (e) => { 
      if (!isDesktop()) return;           // мобилку не трогаем
      e.preventDefault(); 
      e.stopImmediatePropagation(); 
    };

    // мышь/pointer
    toggle.addEventListener('pointerdown', cancel, true);
    toggle.addEventListener('mousedown',   cancel, true);
    toggle.addEventListener('mouseup',     cancel, true);
    toggle.addEventListener('click',       cancel, true);

    // клавиатура (чтобы Enter/Space не триггерили клик)
    toggle.addEventListener('keydown', function(e){
      if (!isDesktop()) return;
      if (e.key === 'Enter' || e.key === ' ') cancel(e);
    }, true);

    // чисто косметика/а11y-подсказка
    toggle.setAttribute('aria-disabled','true'); 
  }

  function bind(){
    if (!isDesktop()) return;
    document.querySelectorAll(scopeToggles).forEach(disableClickOnToggle);
  }

  document.addEventListener('DOMContentLoaded', bind);
  // На случай ресайза между брейкпоинтами
  window.addEventListener('resize', function(){
    // Сначала снимаем старые (перезагрузка страницы — самый простой путь),
    // но для стабильности просто перебиндим: addEventListener с capture не дублируется критично.
    bind();
  });
})();
</script>
<style>
  /* Слои: overlay и меню поверх диммера, шапка — поверх всех */
  .w-nav-overlay {
    z-index: 1198 !important;
  }
  .w-nav-overlay .w-nav-menu {
    position: fixed;
    left: 0;
    right: 0;
    z-index: 1199 !important;
  }

  /* Диммер под меню */
  #menuDimmer {
    position: fixed;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0,0,0,.55);
    opacity: 0;
    pointer-events: none;
    transition: opacity .25s ease;
    z-index: 1197;
  }

  /* Когда меню открыто — фиксируем мобильную шапку и даём ей фон */
  body.mobile-menu-open .navbar-3 {
    position: fixed !important;
    top: 0;
    left: 0;
    right: 0;
    z-index: 1200 !important;
    transform: translateZ(0); /* страховка от глюков в FF */

    /* !!! тут поставь тот же фон, что у .header-container-2 !!! */
    background: #fff; /* пример, замени на свой цвет/градиент */
  }
</style>

<script>
/**
 * Mobile Webflow navbar — Firefox-safe:
 * - при открытии: фиксируем .navbar-3, считаем её высоту
 * - overlay и меню начинаются сразу под шапкой
 * - диммер #menuDimmer под меню
 * - скролл лочится через overflow, без position:fixed на body
 */
(function () {
  const NAVBAR = '.navbar-3';
  const BTN    = `${NAVBAR} .w-nav-button`;
  const OVSEL  = '.w-nav-overlay';
  const MENU   = '.w-nav-overlay .w-nav-menu';
  const MOBILE = '(max-width: 991px)';
  const isMobile = () => window.matchMedia(MOBILE).matches;

  // диммер
  let dimmer = document.getElementById('menuDimmer');
  if (!dimmer) {
    dimmer = document.createElement('div');
    dimmer.id = 'menuDimmer';
    document.body.appendChild(dimmer);
  }

  const $    = (s) => document.querySelector(s);
  const btn  = ()  => $(BTN);
  const ov   = ()  => $(OVSEL);
  const menu = ()  => $(MENU);
  const open = ()  => !!$(`${BTN}.w--open`);

  const lockScroll = () => {
    document.documentElement.style.overflow = 'hidden';
    document.body.style.overflow = 'hidden';
  };
  const unlockScroll = () => {
    document.documentElement.style.overflow = '';
    document.body.style.overflow = '';
  };

  function navHeight(){
    const el = $(NAVBAR);
    const h  = el ? Math.round(el.getBoundingClientRect().height) : 70;
    return h || 70;
  }

  function placeUnderHeader(){
    const h = navHeight();

    // гарантируем, что overlay в body (Firefox)
    const o = ov();
    if (o){
      if (o.parentNode !== document.body) document.body.appendChild(o);
      Object.assign(o.style, {
        position: 'fixed',
        top:      h + 'px',
        left:     '0',
        right:    '0',
        bottom:   '0',
        width:    '100%',
        overflow: 'visible',
        display:  'block',
        pointerEvents: 'auto'
      });
    }

    const m = menu();
    if (m){
      Object.assign(m.style, {
  position: 'fixed',
        top:       h + 'px',
        left:      '0',
        right:     '0',
      bottom:    '0',              // Растягиваем до низа
        overflowY: 'auto',           // Скролл только внутри меню
        maxHeight: 'none',           // Снимаем ограничения Webflow
        WebkitOverflowScrolling: 'touch' // Плавность на iOS
      });
    }

    dimmer.style.top = h + 'px';
  }

  function show(){
    if (!isMobile()) return;

    document.body.classList.add('mobile-menu-open');
    placeUnderHeader();

    dimmer.style.opacity       = '1';
    dimmer.style.pointerEvents = 'auto';

    lockScroll();
  }

function hide(){
  dimmer.style.opacity       = '0';
  dimmer.style.pointerEvents = 'none';

  document.body.classList.remove('mobile-menu-open');
  unlockScroll();

  const o = ov();
  if (o){ // ← убрали проверку !open()
    o.style.pointerEvents = 'none';
    o.style.display       = 'none';
    o.style.height        = ''; // сброс возможных залипаний FF
  }
}


  function sync(){
    if (!isMobile()) {
      hide();
      return;
    }
    if (open()) show(); else hide();
  }

  // клик по бургеру
  document.addEventListener('click', (e) => {
    if (e.target.closest(BTN)) {
      setTimeout(sync, 0);
    }
  });

  // клик по диммеру — закрываем меню
  dimmer.addEventListener('click', () => {
    const b = btn();
    if (b && b.classList.contains('w--open')) b.click();
  });

  // наблюдаем изменения классов/стилей от Webflow
  const mo = new MutationObserver(() => setTimeout(sync, 0));
  mo.observe(document.documentElement, {
    subtree: true,
    childList: true,
    attributes: true,
    attributeFilter: ['class', 'style', 'data-nav-menu-open']
  });

  // при ресайзе/скролле актуализируем позицию
  window.addEventListener('resize', () => {
    if (open()) placeUnderHeader();
    sync();
  }, { passive: true });

  window.addEventListener('scroll', () => {
    if (open()) placeUnderHeader();
  }, { passive: true });

  document.addEventListener('DOMContentLoaded', sync);
})();
</script>
<style>
  /* Глобальный стоп-кран:
     когда меню НЕ открыто (нет класса на body),
     оверлей полностью выключен и не ловит клики */
  body:not(.mobile-menu-open) .w-nav-overlay {
    display: none !important;
    pointer-events: none !important;
    height: auto !important;
  }

  /* Когда меню открыто — даём оверлею клики,
     чтобы работало само меню */
  body.mobile-menu-open .w-nav-overlay {
    pointer-events: auto !important;
  }
  

/* Улучшаем поведение скролла на мобильных */
body.mobile-menu-open .w-nav-overlay .w-nav-menu {
    -webkit-overflow-scrolling: touch;  /* Инерционный скролл для старых iOS */
}
</style></div></div><section class="section_breadcrumbs section-121"><div class="w-layout-blockcontainer container-default breadcrumbs-container w-container"><div class="breadcrumbs-wrapper"><a href="/" class="breadcrumb-link">Home</a><div class="breadcrumb-div">/</div><a href="/blog" class="breadcrumb-link hidden-link">Blog</a><div class="breadcrumb-div hidden-txt">/</div><div class="breadcrumb-text">How to Measure Windows for Replacement?</div></div></div></section><section class="section hero-v4"><div class="w-layout-blockcontainer container-default w-container"><div class="blog-post-single---top-content"><div class="inner-container _770px"><div class="inner-container _550px---tablet"><div class="mg-top-small"><h1 class="display-9 mid">How to Measure Windows for Replacement?</h1></div></div></div></div><div class="mg-top-extra-large"><div data-w-id="36d110dd-4070-3326-4ed6-4282e12132c4" style="opacity:0;-webkit-transform:translate3d(0, 0, 0) scale3d(0.92, 0.92, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0);-moz-transform:translate3d(0, 0, 0) scale3d(0.92, 0.92, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0);-ms-transform:translate3d(0, 0, 0) scale3d(0.92, 0.92, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0);transform:translate3d(0, 0, 0) scale3d(0.92, 0.92, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0)" class="image-wrapper border-radius-image-default"><img src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb1586/688101a136422bbc5a379a18_Measuring-Windows-AdobeStock_896821-scaled.avif" loading="eager" alt="" class="image post---featured-image"/></div></div><div class="mg-top-section-large"><div class="inner-container _690px center"><div class="rich-text-v1 mg-bottom--16px w-richtext"><p>Are you a homeowner who&#x27;s found yourself with cracked glass, leaking window frames, and/or sky-high utility bills? Sounds like it&#x27;s time to figure out how to measure your windows for replacement. Whether you will be ordering new windows online or hiring a professional, measuring your windows correctly is crucial to ensure you get the right fit. Luckily, it&#x27;s simply a matter of following the right guide. In this piece, we will walk you through how to measure your windows so that you can get those replacements in ASAP and stress-free.</p><p>‍</p><h4>Window measuring guide</h4><p>Your basic window measurements will always start with three checks: </p><p>1. Square check<br/>2. Window width<br/>3. Window height</p><p>‍</p><h4>Square check</h4><p>Be sure to always start with the square check. Warning: if your frame doesn&#x27;t pass this test, then a window replacement is out of the question and you&#x27;ll likely need to construct a new window.  The square check determines whether your existing frame measures at 90-degree angles in all four corners. To do this, measure diagonally from the top right corner to the bottom left corner and then from the top left corner to the bottom right corner. If those two measurements are more than ¼ inch apart…call in the professionals. It may be time for a new window frame.  Once you are sure your window frame isn&#x27;t warped, you&#x27;ll want to measure width and height.</p><h6>Pro-tip: Industry standards dictate that width always comes before height. So when you&#x27;re talking to the professionals, make sure you&#x27;ve written your measurements down in that order!</h6><p>‍</p><h4>How to measure window width</h4><p>Measuring window width is a little more complex than one might expect. You&#x27;re going to take <em>three</em> measurements and use <em>the smallest one</em>. </p><p>1. Bottom measurement: raise the window and measure horizontally from left to right jamb. You&#x27;ll include the frame in which the glass sits, but not the trim/jambs themselves.<br/>2. Middle measurement: close the window and measure horizontally from left to right jamb in the middle of the window. <br/>3. Top measurement: measure horizontally from left to right jamb at the top of the window. </p><p>These numbers should all be within ¼ inch of one another. The lowest number of the three is the window width that you&#x27;ll use to order your replacement windows.</p><p>‍</p><h4>How to measure window height</h4><p>Measuring window height is very similar to measuring window width. Once again, you&#x27;ll take three measurements and then use the <em>smallest </em>one to order your perfect window. Measuring from the sill (bottom fixed-frame piece) to the head (top fixed-frame piece), measure vertically once on the left, in the center, and on the right. Then, take the smallest number and use it as your height measurement when looking at window sizes.</p><h4>‍</h4><h4>Special window measurements</h4><p>Now let&#x27;s take a look at a few non-standard measurements. Any window is measurable, some simply take a bit more know-how. Here are a few of the most common special window measurements. </p><figure style="max-width:2048pxpx" class="w-richtext-align-fullwidth w-richtext-figure-type-image"><div><img loading="lazy" alt="" src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb1586/688101d94a1b7da7f6d8d29e_how-to-measure-for-replacement-windows-AdobeStock_280295402-scaled.avif"/></div></figure><h4>How to measure window depth</h4><p>To measure window depth, simply measure the distance between the inside and the outside of the frame on either the top or bottom of the window. It&#x27;s a small and easy measurement, but it can be an essential one.  Depth isn&#x27;t a standard measurement included on most replacement window products because 9 out of 10 times, it&#x27;s not essential for a safe fit. However, if you&#x27;re looking to replace a window in a structure like a modular home, it&#x27;s worth checking the depth. Some modern homes have extremely narrow frames and require specific types of replacements. If the distance from front trim to back trim is less than 3¼ inches, you&#x27;ll need to purchase a custom replacement.</p><p>‍</p><h4>How to measure double-hung windows</h4><p>Double-hung windows sound more intimidating than single-hung, but your process will be nearly identical. The only difference is that you&#x27;ll use the standard measuring process twice. The most important thing to remember when it comes to double-hung windows is to <em>individually measure each pane</em>. Never assume both top and bottom are identical—you may end up with panes that don&#x27;t fit evenly! </p><p>‍</p><h4>How to measure for storm windows</h4><p>Storm windows measure almost identically to standard single-hung windows. The only difference is that you won&#x27;t open the window to measure for width; you&#x27;ll keep it closed for all three measurements.  When measuring storm windows, it&#x27;s extra critical to check for square fit. The last thing you want between you and dangerous weather is a faulty window frame! </p><p>‍</p><h4>How to measure bay or bow windows</h4><p>Bay and bow windows are gorgeous in your home—but they&#x27;re a bit more complex to measure. For these types of windows, you&#x27;ll need the basic width x height measurements for <em>each window panel</em>. You&#x27;ll also need those same measurements for the width and height of the entire window area. At the end of measuring, you should have eight numbers: </p><p>- Right panel (WxH)<br/>- Center panel (WxH)<br/>- Left panel (WxH)<br/>- Entire window (WxH)</p><p>‍</p><h4>How to measure for window screen replacements</h4><p>Window screen replacements are thankfully much more straightforward than window panes. For window screen measurements, all you&#x27;ll need is a single width x height number. We recommend adding about ⅛ inch to your screen measurements before purchasing, though. Different screens may fit differently, depending on the brand. Adding an extra ⅛ inch assures a snug fit.</p><p>‍</p><h4>Replacing a window with a different style</h4><p>Not every window replacement is motivated by damage. Often, proactive homeowners will upgrade their windows for aesthetic reasons and/or energy efficiency! When changing window styles, you&#x27;ll have an opportunity to open up your space in a whole new way, but there are a few things to track:</p><p>- Is there anything permanent outside the window? Many standard windows open up and down by sliding, but casement windows (which crank open on a side hinge) can be a lovely way to add a bit of flair—if there&#x27;s room. Just because a window fits your frame doesn&#x27;t mean it fits the entire window area. If you&#x27;re switching to a window that opens out of or into your home, make sure you know how much space you&#x27;ll need for the swinging panes.  </p><p>- Will a different type of glass affect the temperature in a negative way?<strong> </strong>One of the key jobs of windows is to regulate internal temperature. However, depending on the type of glass, items next to windows can have very different experiences. If you&#x27;re replacing a window near old furniture or growing plants, the type and thickness of glass may impact their sun and temperature exposure.</p><p>On the other hand, upgrading from single-pane to double-pane windows is a great way to increase your home&#x27;s energy efficiency and lower your seasonal utility bills. Often, window upgrades lead to more consistent home temperatures, meaning happier residents of both the human and plant variety.</p><p>‍</p><h4>How to order replacement windows</h4><p>There are two ways to order windows depending on whether you&#x27;re looking for professional installation or taking the DIY route.  If you&#x27;re in the DIY camp, the best way to order your windows is from a reliable home improvement store like Lowe&#x27;s or Home Depot. Not only do they carry multiple brands, but you can also visit their stores to see different types of windows in person and decide on your preferred style and glass type. </p><p>Of course, we recommend using the professional approach. DIY is fantastic for people who know what they&#x27;re doing, but for most of us, it&#x27;s best to leave a delicate operation like window installation to the experts. Windows protect your home from burglary, dust, weather, insects, and mold. A poorly selected or installed window isn&#x27;t just an inconvenience—it can lead to some pretty expensive consequences. </p><p>When you work with a professional window company, you&#x27;ll have the peace of mind that comes from knowing your measurements are accurate, your replacement is up to code, and your windows are under warranty. </p><p>‍</p><h4>How to order replacement windows</h4><p>Windows aren&#x27;t all created equally, so the cost of replacements varies quite a bit based on: </p><p>- Window style (double hung, sliding, vent, etc)<br/>- Window size<br/>- Window material (vinyl, wood, etc)<br/>- State of the window frame (and whether or not frame replacement is also required)<br/>- Type of glass (single-pane, double-pane, laminated, etc)<br/>- The age of your home and any age-related restrictions by local law</p><p>Additionally, with the rising cost of utilities, energy efficiency is a top priority for many homeowners today. Energy-efficient windows come in all shapes and sizes—double- or triple-pane windows with argon gas filling are more than twice as energy efficient as your typical single-pane window! However, these styles do come with a higher price tag. Though your energy-efficient windows will recoup that investment in reduced utility bills over time, their higher starting cost is worth considering if you&#x27;re on a budget.    Your window replacement <em>installation</em> cost will also depend on your decision to use professional services or DIY. The costs of paying for labor vs. supplies will affect your overall investment. </p></div></div></div></div></section><section class="section pd-120px"><div class="w-layout-blockcontainer container-default w-container"><div class="title-left---content-right"><div class="width-100-mobile-portrait"><h2 class="display-8 mid">Read More Articles</h2></